#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int *tweets = (int *)calloc(N, sizeof(int));
        int openCount = 0;
        for (int i = 0; i < K; ++i) {
            char cmd[10];
            scanf("%s", cmd);
            if (strcmp(cmd, "CLICK") == 0) {
                int X; scanf("%d", &X); --X;
                if (tweets[X] == 0) { tweets[X] = 1; ++openCount; }
                else { tweets[X] = 0; --openCount; }
            } else { // CLOSEALL
                memset(tweets, 0, N * sizeof(int));
                openCount = 0;
            }
            printf("%d\n", openCount);
        }
        free(tweets);
    }
    return 0;
}

